-- ── Portfoleon ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Portfoleon is a product portfolio and roadmapping tool that helps product teams visualize roadmaps, manage a portfolio of initiatives, and align projects with strategic goals using drag-and-drop timeline boards.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 10 users); paid plans from $24/user/month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Huldenberg, Belgium$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Portfoleon Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Portfoleon review: product portfolio roadmapping with drag-and-drop boards. Compare pricing tiers, features and alternatives before you buy.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Portfoleon is a product portfolio management and roadmapping tool designed to help product managers, PMOs and leadership teams visualize strategic initiatives, projects and releases on drag-and-drop timeline boards, and connect day-to-day roadmap items back to higher-level company objectives. The company is privately held and headquartered in Huldenberg, Belgium, run by a small, lean team; public sources describe a core team of around three people handling product, technology and portfolio management, which sets Portfoleon apart from larger, venture-funded roadmapping vendors as a bootstrapped, founder-operated tool. Its main differentiator versus generic project management software is its focus specifically on portfolio-level strategy execution: rather than tracking granular tasks like Jira or Asana, Portfoleon lets teams build multiple linked boards (roadmaps, portfolios, OKR trees) with custom fields, dependencies, and drafts/revisions so that strategic plans can be iterated on before being published to stakeholders. Portfoleon offers a free tier that is usable indefinitely, supporting up to two portfolios, five boards, five custom fields and up to ten users, with unlimited items and access to the drafts-and-revisions workflow, making it accessible to small teams and startups without a credit card. Paid tiers scale usage and functionality: a Roadmapping plan priced at $24 per user per month is aimed at small teams needing core roadmap features, and a Portfolio plan at $48 per user per month unlocks more advanced portfolio management, multi-level rollups and governance features for growing organizations, while an Enterprise tier is quoted on request for large organizations needing custom deployment, security or support terms. Portfoleon's target users are product managers, portfolio managers, PMOs and executives who need a single visual source of truth for what the organization is building and why, particularly in mid-size to large companies running multiple concurrent product lines or programs. Its most direct competitors in the roadmapping and portfolio space include ProductPlan, Aha!, Roadmunk and Jira Product Discovery, as well as broader project/portfolio management tools like Monday.com and Smartsheet when used for roadmapping; Portfoleon differentiates from these primarily through its lower price point, simpler learning curve, and explicit focus on linking strategy to execution through its portfolio-and-board hierarchy rather than being a general-purpose project tracker.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4754e964-cca0-48dc-adc6-88e29e111bd1';

