-- ── PostgREST ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PostgREST is a free, open-source standalone web server that turns an existing PostgreSQL database directly into a RESTful API, generating endpoints from database tables, views and stored procedures without custom backend code.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (open-source community project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed open-source community)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PostgREST Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PostgREST review: instantly turn a PostgreSQL database into a REST API. Features, setup, pricing and alternatives compared for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PostgREST is a free, open-source, standalone web server, written in Haskell using the Warp HTTP framework, that automatically generates a fully RESTful API directly from an existing PostgreSQL database's schema. It was created by developer Joe Nelson (online handle begriffs) with an initial public release and announcement around late 2014, and is now maintained by a small group of open-source contributors, with Steve Chavez (also a Supabase engineer) as a long-time active maintainer; the project has no separate company or headquarters and is released under the MIT license. PostgREST's core idea is to eliminate the need to hand-write CRUD API endpoints: it inspects a Postgres database's tables, views and stored procedures/functions and exposes them as REST resources automatically, using HTTP verbs and query parameters to handle filtering, sorting, pagination and embedding of related resources. Rather than handling authorization in application code, PostgREST delegates security to PostgreSQL's own role-based access control and row-level security policies, decoding JSON Web Tokens (JWTs) to switch the database role for each request, so there is a single declarative source of truth for permissions living inside the database itself. This architecture makes PostgREST especially popular for rapid backend development, internal tooling, and as an infrastructure building block: most notably, PostgREST powers the auto-generated REST API layer inside Supabase, the popular open-source Firebase alternative, which has significantly increased its visibility and adoption since Supabase's growth. It is entirely free and open source with no paid tier of its own, since it is a developer tool rather than a hosted product; any cost comes from the PostgreSQL database and any infrastructure a team runs it on. PostgREST's target users are backend and full-stack developers who want to skip writing boilerplate API code, teams building internal or admin tooling, and platforms like Supabase that embed it as infrastructure. It should not be confused with PostgreSQL itself, which is the underlying relational database; PostgREST is a separate, complementary tool that sits in front of a Postgres database to expose it over HTTP. Its closest comparison points and competitors include Hasura (which generates GraphQL rather than REST APIs from a database), PostGraphile (GraphQL from Postgres), Supabase's broader platform (which bundles PostgREST alongside auth, storage and realtime features), and hand-built REST frameworks like Django REST Framework or Express-based APIs, which PostgREST is designed to make largely unnecessary for straightforward CRUD use cases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dd33727e-2e57-4b2e-af05-7dee39588471';

