-- ── posthog ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PostHog is an open-source product analytics platform combining event analytics, session replay, feature flags, A/B testing and surveys in one suite, aimed at engineering-led product teams.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (generous usage limits); paid plans are usage-based after free allowances$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$101-250 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PostHog Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PostHog review: open-source product analytics with session replay, feature flags and A/B testing. Compare pricing tiers and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PostHog is an open-source product analytics platform that bundles event-based analytics, session replay, feature flags, A/B testing and experimentation, surveys, error tracking, and a data warehouse into a single integrated suite, positioned as an all-in-one alternative to stitching together separate tools like Google Analytics, Mixpanel, Amplitude, LaunchDarkly, Hotjar and Optimizely. It was founded on January 23, 2020 by James Hawkins (CEO) and Tim Glaser (CTO), who met while working at London regulatory-tech startup Arachnys, and went through Y Combinator; the company is headquartered in San Francisco, California, with a globally distributed remote team of roughly 100-200 employees. PostHog has raised significant venture funding, including a $3M seed round in March 2020, a $9M Series A, a $15M Series B led by Y Combinator, a $70M Series D in June 2024 led by Stripe at a $920M valuation, and a $75M Series E in September 2025, bringing total funding to roughly $194M at a valuation near $1.4B. PostHog's core differentiator is its open-source, developer-first, all-in-one approach: rather than buying separate point solutions for analytics, replay, flags and experimentation, engineering-led product teams install a single SDK and get all of these capabilities from one data model, with self-hosting available for teams that want to keep data in their own infrastructure alongside PostHog's managed cloud offering. Pricing is usage-based with a notably generous free tier -- PostHog states more than 90 percent of companies use it for free -- offering monthly allowances such as 1 million analytics events, 5,000 session replays, 1 million feature flag requests and 1,500 survey responses at no cost, with metered pricing per unit (for example, roughly $0.00005 per event) kicking in beyond those limits and volume discounts at higher usage. Paid usage unlocks additional projects, longer data retention (up to 7 years versus 1 year on the free tier) and email support. PostHog's target users are startups and product-led engineering teams that want deep, self-serve product analytics without a lengthy sales process, as well as larger organizations that value the open-source, self-hostable nature of the platform for data control. Its primary named competitors include Mixpanel and Amplitude for product analytics, Google Analytics for web analytics, LaunchDarkly for feature flags, Hotjar and FullStory for session replay, and Optimizely for A/B testing, all of which PostHog positions itself against by consolidating their functionality into one platform and billing model.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd0c0a6d4-b565-4bc1-aaae-f64d2b455fe7';

